import styles from './SignalPanel.module.css';
import { formatPrice } from '../utils/helpers';

export default function SignalPanel({ signal, indicators, fearGreed, supportRes }) {
  const inds = indicators || {};

  const rsiClass      = !inds.rsi ? 'neutral' : inds.rsi < 38 ? 'bullish' : inds.rsi > 62 ? 'bearish' : 'neutral';
  const macdClass     = (inds.macd || 0) >= 0 ? 'bullish' : 'bearish';
  const emaClass      = inds.emaCross ? 'bullish' : 'bearish';
  const bbClass       = !inds.bbPos ? 'neutral' : inds.bbPos < 25 ? 'bullish' : inds.bbPos > 75 ? 'bearish' : 'neutral';
  const stochClass    = !inds.stochRSI ? 'neutral' : inds.stochRSI < 20 ? 'bullish' : inds.stochRSI > 80 ? 'bearish' : 'neutral';

  const fgColor = !fearGreed ? '#4a5568' :
    fearGreed.value <= 25 ? '#ff3d71' :
    fearGreed.value <= 45 ? '#ffaa00' :
    fearGreed.value <= 55 ? '#4a5568' :
    fearGreed.value <= 75 ? '#00d4ff' : '#00f5a0';

  const fgLabel = !fearGreed ? '—' :
    fearGreed.value <= 25 ? '😱 Aşırı Korku' :
    fearGreed.value <= 45 ? '😨 Korku' :
    fearGreed.value <= 55 ? '😐 Nötr' :
    fearGreed.value <= 75 ? '😊 Açgözlülük' : '🤑 Aşırı Açgözlülük';

  return (
    <div className={styles.panel}>
      <div className={styles.sectionTitle}>⚡ AL / SAT SİNYALİ</div>

      {/* Ana sinyal */}
      <div className={`${styles.mainSignal} ${signal ? styles[signal.cls] : ''}`}>
        <div className={styles.sigIcon}>{signal?.icon || '⏳'}</div>
        <div className={styles.sigLabel}>{signal?.type || 'ANALİZ'}</div>
        <div className={styles.sigConf}>
          {signal ? `Güven skoru: ${signal.successRate}%` : 'Coin seçin veya arayın'}
        </div>
      </div>

      {/* Başarı oranı */}
      {signal?.successRate && (
        <div className={styles.successBox}>
          <div className={styles.successLabel}>Başarı Oranı</div>
          <div className={styles.successNum}>{signal.successRate}%</div>
          <div className={styles.bar}>
            <div className={styles.fill} style={{ width: `${signal.successRate}%` }} />
          </div>
        </div>
      )}

      {/* Fear & Greed */}
      <div className={styles.fgBox} style={{ borderColor: fgColor + '44' }}>
        <div className={styles.fgLeft}>
          <div className={styles.fgTitle}>Fear & Greed Index</div>
          <div className={styles.fgLabel} style={{ color: fgColor }}>{fgLabel}</div>
        </div>
        <div className={styles.fgValue} style={{ color: fgColor }}>
          {fearGreed?.value ?? '—'}
        </div>
      </div>

      {/* Destek / Direnç */}
      {supportRes && (
        <div className={styles.srBox}>
          <div className={styles.srItem}>
            <span className={styles.srLabel}>🟢 Destek</span>
            <span className={styles.srValue} style={{ color: 'var(--accent)' }}>
              {formatPrice(supportRes.support)}
            </span>
          </div>
          <div className={styles.srDivider} />
          <div className={styles.srItem}>
            <span className={styles.srLabel}>🔴 Direnç</span>
            <span className={styles.srValue} style={{ color: 'var(--red)' }}>
              {formatPrice(supportRes.resistance)}
            </span>
          </div>
        </div>
      )}

      {/* İndikatörler */}
      <div className={styles.indGrid}>
        <IndCard label="RSI (14)"    value={inds.rsi || '—'}         cls={rsiClass}   sig={rsiClass === 'bullish' ? '↑ Aşırı Satım' : rsiClass === 'bearish' ? '↓ Aşırı Alım' : '→ Nötr'} />
        <IndCard label="MACD"        value={inds.macd !== undefined ? (inds.macd > 0 ? '+' + inds.macd : inds.macd) : '—'} cls={macdClass}  sig={macdClass === 'bullish' ? '↑ Pozitif' : '↓ Negatif'} />
        <IndCard label="EMA 50/200"  value={inds.emaCross !== undefined ? (inds.emaCross ? '50 > 200' : '50 < 200') : '—'} cls={emaClass}   sig={emaClass === 'bullish' ? '↑ Golden X' : '↓ Death X'} />
        <IndCard label="Bollinger"   value={inds.bbPos !== undefined ? inds.bbPos + '%' : '—'} cls={bbClass}   sig={bbClass === 'bullish' ? '↑ Alt Bant' : bbClass === 'bearish' ? '↓ Üst Bant' : '→ Orta'} />
        <IndCard label="Stoch RSI"   value={inds.stochRSI || '—'}    cls={stochClass} sig={stochClass === 'bullish' ? '↑ Aşırı Satım' : stochClass === 'bearish' ? '↓ Aşırı Alım' : '→ Nötr'} />
        <IndCard label="ATR"         value={inds.atr || '—'}         cls="neutral"    sig="Volatilite" />
      </div>

      {/* Sinyal açıklaması */}
      {signal?.reason && (
        <div className={styles.reason}>
          {signal.reason.split('\n').map((line, i) => (
            <div key={i}>{line}</div>
          ))}
        </div>
      )}
    </div>
  );
}

function IndCard({ label, value, cls, sig }) {
  return (
    <div className={styles.indCard}>
      <div className={styles.indLabel}>{label}</div>
      <div className={`${styles.indValue} ${styles[cls]}`}>{value}</div>
      <div className={`${styles.indSig} ${styles[cls]}`}>{sig}</div>
    </div>
  );
}
